(() => {
  const content = $json.choices?.[0]?.message?.content;
  if (!content) return { error: 'No response from routing engine' };
  try {
    const data = JSON.parse(content);
    const url = 'https://calendly.com/leados2-hackathon-neobim/30min';
    if (data.routed_leads) {
      data.routed_leads = data.routed_leads.map(lead => {
        lead.calendly_link = (lead.final_decision === 'SALES_CALL' || lead.final_decision === 'CHECKOUT') ? url : null;
        return lead;
      });
    }
    return data;
  } catch (e) {
    return { error: 'Invalid JSON from routing engine', raw: content.substring(0, 200) };
  }
})()
}}
